command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: performance}
  - {id: m2, dimension: efficiency_and_flow}
' > space/metrics.yaml && printf 'dimensions:
  performance: {enabled: true}
  efficiency_and_flow: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml 2>out.txt && echo ok 1>&2
